module RefModule(  
    input clk,  
    input reset,  
    input [3:0] frequency,  
    output reg signal  
);  
      wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge reset or posedge dbg_halt) begin  
        if (reset)  
            signal <= 0;  
        else if (frequency >= 4'b1000 && frequency <= 4'b1100)  
            signal <= 1;  
        else  
            signal <= 0;  
    end  
endmodule
